+    fn ring_buffer_prefers_evicting_low_severity_first() {
+        let ring = EventRingBuffer::with_capacity(3);
+        let _ = ring.push(MailEvent::message_sent(
+            1,
+            "A",
+            vec!["B".to_string()],
+            "m1",
+            "t1",
+            "p",
+        ));
